# Interceptor for global error handling
class ErrorHandlingInterceptor(grpc.ServerInterceptor):
    def __init__(self):
        self.error_handler = DetailedErrorService()
    
    def intercept_service(self, continuation, handler_call_details):
        try:
            return continuation(handler_call_details)
        except Exception as e:
            error_details = self.error_handler._format_error_details(
                e,
                context_info={
                    'method': handler_call_details.method,
                    'interceptor': 'ErrorHandlingInterceptor'
                }
            )
            
            def error_handler(request, context):
                context.set_code(grpc.StatusCode.UNKNOWN)
                context.set_details(error_details)
                return None
            
            return grpc.unary_unary_rpc_method_handler(
                error_handler,
                request_deserializer=None,
                response_serializer=None
            )


